// Incoming error event payload
const errorData = $json.body || $json;

// Track errors in static data with a rolling 1-hour window
const staticData = $getWorkflowStaticData('global');
if (!staticData.errors) staticData.errors = [];

const now = Date.now();
const ONE_HOUR = 60 * 60 * 1000;

// Add this error
staticData.errors.push({
  timestamp: now,
  type: errorData.error_type || errorData.type || 'unknown',
  message: errorData.message || errorData.error || 'No message',
  endpoint: errorData.endpoint || errorData.path || 'unknown'
});

// Prune errors older than 1 hour
staticData.errors = staticData.errors.filter(e => now - e.timestamp < ONE_HOUR);

const errorCount = staticData.errors.length;
const shouldAlert = errorCount > 3;

// Get unique error types for summary
const errorTypes = [...new Set(staticData.errors.map(e => e.type))];
const latestError = staticData.errors[staticData.errors.length - 1];

return [{
  json: {
    shouldAlert,
    errorCount,
    errorTypes: errorTypes.join(', '),
    latestMessage: latestError.message,
    latestEndpoint: latestError.endpoint,
    windowStart: new Date(now - ONE_HOUR).toISOString(),
    checkedAt: new Date(now).toISOString()
  }
}];

